import Database from "better-sqlite3";
import { existsSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";

// This module must only ever be imported from server-only boundaries
// (routeLoader$ / routeAction$) so that the native better-sqlite3
// binding never leaks into the client bundle.

export interface NoteRow {
  id: number;
  title: string;
  content: string;
  created_at: string;
  updated_at: string;
}

const DB_PATH = join(process.cwd(), "data", "notes.db");

let db: Database.Database | undefined;

function getDb(): Database.Database {
  if (db) return db;

  const dir = dirname(DB_PATH);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  db = new Database(DB_PATH);
  db.pragma("journal_mode = WAL");
  db.exec(`
    CREATE TABLE IF NOT EXISTS notes (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      content TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    );
  `);

  return db;
}

export function listNotes(): NoteRow[] {
  return getDb()
    .prepare(
      "SELECT id, title, content, created_at, updated_at FROM notes ORDER BY updated_at DESC, id DESC",
    )
    .all() as NoteRow[];
}

export function getNote(id: number): NoteRow | undefined {
  return getDb()
    .prepare(
      "SELECT id, title, content, created_at, updated_at FROM notes WHERE id = ?",
    )
    .get(id) as NoteRow | undefined;
}

export function createNote(title: string, content: string): NoteRow {
  const result = getDb()
    .prepare(
      "INSERT INTO notes (title, content, created_at, updated_at) VALUES (?, ?, datetime('now'), datetime('now'))",
    )
    .run(title, content);
  return getNote(Number(result.lastInsertRowid))!;
}

export function updateNote(
  id: number,
  title: string,
  content: string,
): NoteRow | undefined {
  getDb()
    .prepare(
      "UPDATE notes SET title = ?, content = ?, updated_at = datetime('now') WHERE id = ?",
    )
    .run(title, content, id);
  return getNote(id);
}

export function deleteNote(id: number): boolean {
  const result = getDb().prepare("DELETE FROM notes WHERE id = ?").run(id);
  return result.changes > 0;
}

import MarkdownIt from "markdown-it";
import sanitizeHtml from "sanitize-html";

// Server-only helper: converts Markdown source into sanitized HTML that is
// safe to render via dangerouslySetInnerHTML on the client.

const md = new MarkdownIt({
  html: false, // never trust raw HTML embedded in the markdown source
  linkify: true,
  breaks: true,
});

export function renderMarkdownToSafeHtml(markdown: string): string {
  const rawHtml = md.render(markdown ?? "");

  return sanitizeHtml(rawHtml, {
    allowedTags: [
      "h1",
      "h2",
      "h3",
      "h4",
      "h5",
      "h6",
      "p",
      "a",
      "ul",
      "ol",
      "li",
      "blockquote",
      "code",
      "pre",
      "strong",
      "em",
      "hr",
      "br",
      "table",
      "thead",
      "tbody",
      "tr",
      "th",
      "td",
      "img",
      "del",
      "s",
    ],
    allowedAttributes: {
      a: ["href", "name", "target", "rel"],
      img: ["src", "alt", "title"],
      code: ["class"],
      pre: ["class"],
    },
    allowedSchemes: ["http", "https", "mailto"],
    transformTags: {
      a: sanitizeHtml.simpleTransform("a", {
        rel: "noopener noreferrer nofollow",
        target: "_blank",
      }),
    },
  });
}

import { component$ } from "@builder.io/qwik";
import {
  routeLoader$,
  routeAction$,
  zod$,
  z,
  Link,
} from "@builder.io/qwik-city";
import { createNote, deleteNote, listNotes } from "~/lib/db";

export const useNotesLoader = routeLoader$(() => {
  return listNotes();
});

export const useCreateNoteAction = routeAction$(
  (data) => {
    const note = createNote(data.title.trim(), data.content.trim());
    return {
      success: true as const,
      note,
    };
  },
  zod$({
    title: z.string().trim().min(1, "Title is required"),
    content: z.string().trim().min(1, "Content is required"),
  }),
);

export const useDeleteNoteAction = routeAction$(
  (data) => {
    const ok = deleteNote(data.id);
    return { success: ok };
  },
  zod$({
    id: z.coerce.number().int().positive(),
  }),
);

export default component$(() => {
  const notes = useNotesLoader();
  const createAction = useCreateNoteAction();
  const deleteAction = useDeleteNoteAction();

  return (
    <>
      <h1>Markdown Notes</h1>

      <section>
        <h2>New note</h2>
        <Form action={createAction}>
          <div>
            <label for="title">Title</label>
            <br />
            <input
              id="title"
              name="title"
              type="text"
              value={createAction.formData?.get("title")?.toString() ?? ""}
            />
          </div>
          <div>
            <label for="content">Content (Markdown)</label>
            <br />
            <textarea
              id="content"
              name="content"
              rows={8}
              cols={60}
            >
              {createAction.formData?.get("content")?.toString() ?? ""}
            </textarea>
          </div>

          {createAction.value?.failed && (
            <div role="alert" style={{ color: "red" }}>
              {createAction.value.fieldErrors?.title && (
                <p>{createAction.value.fieldErrors.title}</p>
              )}
              {createAction.value.fieldErrors?.content && (
                <p>{createAction.value.fieldErrors.content}</p>
              )}
            </div>
          )}

          <button type="submit">Create note</button>
        </Form>
      </section>

      <section>
        <h2>All notes</h2>
        {notes.value.length === 0 && <p>No notes yet.</p>}
        <ul>
          {notes.value.map((note) => (
            <li key={note.id}>
              <Link href={`/notes/${note.id}/`}>{note.title}</Link>{" "}
              <Link href={`/notes/${note.id}/edit/`}>edit</Link>{" "}
              <Form action={deleteAction} style={{ display: "inline" }}>
                <input type="hidden" name="id" value={note.id} />
                <button type="submit">delete</button>
              </Form>
            </li>
          ))}
        </ul>
      </section>
    </>
  );
});

